import { Server } from '@modelcontextprotocol/sdk/server/index.js';
const skills = await client.readContract({ address: SKILL_CRED, abi, functionName: 'getAgentSkills', args: [agent] });
const server = new Server({ name: 'normie-' + tokenId, version: '1.0.0' }, { capabilities: { tools: {} } });
server.setRequestHandler(ListToolsRequestSchema, async () => ({ tools: skills.map(toolFromSkillId) }));
server.setRequestHandler(CallToolRequestSchema, async (req) => { return await invokeSkill(req.params); });
await server.connect(transport);
